import "dotenv/config";
import { ApolloServer } from "@apollo/server";
import { ApolloServerPluginDrainHttpServer } from "@apollo/server/plugin/drainHttpServer";
import { expressMiddleware } from "@as-integrations/express5";
import { makeExecutableSchema } from "@graphql-tools/schema";
import cors from "cors";
import express from "express";
import { useServer } from "graphql-ws/use/ws";
import jwt from "jsonwebtoken";
import { createServer } from "node:http";
import { WebSocketServer } from "ws";

import {
  startChatEventsConsumer,
  stopChatEventsConsumer,
} from "./chatEventsConsumer.js";
import { grpcClients } from "./grpcClients.js";
import { resolvers } from "./resolvers.js";
import { typeDefs } from "./schema.js";

const PORT = Number(process.env.PORT ?? 4000);
const JWT_SECRET = process.env.JWT_SECRET ?? "your_jwt_secret";

const COURSE_SERVICE_URL =
  process.env.COURSE_HTTP_URL || "http://localhost:4001";
const ENROLLMENT_SERVICE_URL =
  process.env.ENROLLMENT_HTTP_URL || "http://localhost:4002";

function getUserFromToken(token) {
  if (!token) {
    return null;
  }
  try {
    const payload = jwt.verify(token, JWT_SECRET);
    return {
      studentId: payload.studentId ?? payload.sub,
      email: payload.email,
      name: payload.name,
    };
  } catch {
    return null;
  }
}

function getTokenFromAuthorizationHeader(authorization = "") {
  if (!authorization.startsWith("Bearer ")) {
    return null;
  }
  return authorization.slice("Bearer ".length);
}

function getTokenFromConnectionParams(connectionParams = {}) {
  const raw =
    connectionParams.authentication ??
    connectionParams.Authorization ??
    connectionParams.authorization;
  if (typeof raw !== "string") {
    return null;
  }
  if (raw.startsWith("Bearer ")) {
    return raw.slice("Bearer ".length);
  }
  return raw;
}

function createContext(user, extra = {}) {
  return {
    user,
    currentStudentId: user?.studentId ?? null,
    grpc: grpcClients,
    courseServiceUrl: COURSE_SERVICE_URL,
    enrollmentServiceUrl: ENROLLMENT_SERVICE_URL,
    ...extra,
  };
}

const app = express();
const httpServer = createServer(app);

const schema = makeExecutableSchema({
  typeDefs,
  resolvers,
});

const wsServer = new WebSocketServer({
  server: httpServer,
  path: "/graphql",
});

const serverCleanup = useServer(
  {
    schema,
    context: async (ctx) => {
      const token = getTokenFromConnectionParams(ctx.connectionParams);
      const user = getUserFromToken(token);
      return createContext(user);
    },
    onConnect: async (ctx) => {
      const token = getTokenFromConnectionParams(ctx.connectionParams);
      const user = getUserFromToken(token);
      if (!user) {
        throw new Error("Unauthorized");
      }
      return true;
    },
  },
  wsServer
);

const server = new ApolloServer({
  schema,
  plugins: [
    ApolloServerPluginDrainHttpServer({ httpServer }),
    {
      async serverWillStart() {
        return {
          async drainServer() {
            await serverCleanup.dispose();
            await stopChatEventsConsumer();
          },
        };
      },
    },
  ],
});

await server.start();

app.use(
  "/graphql",
  cors({
    origin: ["http://localhost:5173", "http://localhost:3000"],
    credentials: true,
  }),
  express.json(),
  expressMiddleware(server, {
    context: async ({ req }) => {
      const token = getTokenFromAuthorizationHeader(req.headers.authorization);
      const user = getUserFromToken(token);
      return createContext(user, {
        correlationId: req.headers["x-correlation-id"] ?? null,
      });
    },
  })
);

app.get("/health", (req, res) => {
  res.json({
    service: "graphql-gateway",
    status: "ok",
    graphql: "/graphql",
    subscriptions: `ws://localhost:${PORT}/graphql`,
    timestamp: new Date().toISOString(),
  });
});

await startChatEventsConsumer();

httpServer.listen(PORT, () => {
  console.log(
    `[graphql-gateway] HTTP GraphQL ready at http://localhost:${PORT}/graphql`
  );
  console.log(
    `[graphql-gateway] WS subscriptions ready at ws://localhost:${PORT}/graphql`
  );
});
